using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old name so existing documents and raw SQL
        // (e.g. SELECT * FROM c WHERE c.Discriminator = 'Blog') keep working.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change #2: id no longer includes the discriminator.
        // Existing documents have id = "Blog|1"; without this flag EF would
        // look for id = "1" and never find them.
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // Breaking change #3: HasIndex now throws on Cosmos (was silently ignored).
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

